SELECT txn_id, payer_account_id, payee_account_id, amount, currency, status, created_time, updated_time
FROM transaction_record
WHERE txn_id = #{txnId}

SELECT txn_id, payer_account_id, payee_account_id, amount, currency, status, created_time, updated_time
FROM transaction_record
WHERE txn_id = #{txnId}
ORDER BY created_time DESC
LIMIT #{pageSize} OFFSET #{pageNo}
